    """
    Wrapper for Features which acts on a copy of itself but keeps
    `_column_requires_decoding` in sync with the underlying dict content
    after the wrapped mutating method returns.
    """

    @wraps(func)
    def wrapper(*args, **kwargs):
        if args:
            self: "Features" = args[0]
            args = args[1:]
        else:
            self: "Features" = kwargs.pop("self")
        out = func(self, *args, **kwargs)
        assert hasattr(self, "_column_requires_decoding")
        self._column_requires_decoding = {col: require_decoding(feature) for col, feature in self.items()}
        return out

    wrapper._decorator_name_ = "wraps"
    return wrapper


